sql:
SELECT message 
FROM notifications 
WHERE notification_date = (SELECT MAX(notification_date) FROM notifications);

SELECT first_name, last_name
FROM customers
WHERE customer_id IN (
  SELECT customer_id
  FROM customer_acquisition
  WHERE acquisition_cost = (
    SELECT MAX(acquisition_cost)
    FROM customer_acquisition
  )
);

